1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	type QuoteResult = { premium: number };
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  amulet: 60,
21	  sword: 100,
22	  rune: 25,
23	};
24	
25	const FIRST_INSURANCE_RATE = 0.1;
26	const PROCESSING_FEE = 5;
27	
28	const CURSE_SURCHARGE_RATE = 0.5;
29	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const LOYALTY_DISCOUNT_RATE = 0.2;
32	const LOYALTY_THRESHOLD_YEARS = 2;
33	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
34	
35	function sumOver<T>(xs: T[], f: (x: T) => number): number {
36	  return xs.reduce((total, x) => total + f(x), 0);
37	}
38	
39	// MHPCO rounds quote premiums UP (in the office's favor).
40	function roundUpInFavorOfOffice(amount: number): number {
41	  return Math.ceil(amount);
42	}
43	
44	function itemBasePremium(item: QuoteItem): number {
45	  return BASE_PREMIUM[item.type] ?? 0;
46	}
47	
48	function itemSurcharges(item: QuoteItem): number {
49	  const base = itemBasePremium(item);
50	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
51	  const highEnchantmentSurcharge =
52	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
53	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
54	      : 0;
55	  return curseSurcharge + highEnchantmentSurcharge;
56	}
57	
58	function priceQuoteStep(
59	  step: QuoteStep,
60	  yearsWithMHPCO: number,
61	  isFollowUp: boolean,
62	): QuoteResult {
63	  const policyBase = sumOver(step.items, itemBasePremium);
64	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
65	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
66	  const loyaltyDiscount =
67	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
68	      ? policyBase * LOYALTY_DISCOUNT_RATE
69	      : 0;
70	  const followUpDiscount = isFollowUp
71	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
72	    : 0;
73	  const premium = roundUpInFavorOfOffice(
74	    policyBase +
75	      itemSurchargeTotal +
76	      firstInsurance -
77	      loyaltyDiscount -
78	      followUpDiscount +
79	      PROCESSING_FEE,
80	  );
81	  return { premium };
82	}
83	
84	export function runScenario(scenario: Scenario): {
85	  results: QuoteResult[];
86	} {
87	  const results = scenario.steps.map((step, index) =>
88	    priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0),
89	  );
90	  return { results };
91	}
